#!/usr/bin/env python3
"""Create joy2midi icon files from an embedded app logo image."""
from __future__ import annotations

import base64
from pathlib import Path

ICON_PNG_B64 = """

"""


def main() -> None:
    png_path = Path("app_icon.png")
    ico_path = Path("app_icon.ico")
    png_path.write_bytes(base64.b64decode("".join(ICON_PNG_B64.split())))
    try:
        from PIL import Image
        img = Image.open(png_path).convert("RGBA")
        img.save(ico_path, format="ICO", sizes=[(16, 16), (32, 32), (48, 48), (64, 64), (128, 128), (256, 256)])
        print(f"Wrote {png_path} and {ico_path}")
    except Exception as exc:
        print(f"Wrote {png_path}; could not create .ico: {exc}")


if __name__ == "__main__":
    main()
